178→fn canonicalize_schema_for_openai_compat(schema: &serde_json::Value) -> serde_json::Value {
179→    // Strip `$schema` so `SchemaDocument::from_json()` doesn't reject
180→    // non-2020-12 drafts (e.g. draft-07 from Attio MCP tools, issue #743).
181→    // Draft-07 and 2020-12 share enough structural keywords that
182→    // canonicalization works; remaining differences (`definitions` vs
183→    // `$defs`, tuple `items` vs `prefixItems`) are handled by schemars
184→    // transforms downstream. `$schema` itself is later stripped by
185→    // `OpenAiSchemaSubsetTransform` anyway.
186→    let mut input = schema.clone();
187→    if let Some(obj) = input.as_object_mut() {
188→        obj.remove("$schema");
189→    }
190→
191→    let document = match SchemaDocument::from_json(&input) {
192→        Ok(document) => document,
193→        Err(error) => {
194→            warn!(
195→                error = %error,
196→                "openai tool schema failed Draft 2020-12 preflight; using raw schema for best-effort normalization"
197→            );
198→            return input;
199→        },
200→    };
201→
202→    if let Err(error) = document.root() {
203→        warn!(
204→            error = %error,
205→            "openai tool schema failed canonical AST resolution; using raw schema for best-effort normalization"
206→        );
207→        return input;
208→    }
209→
210→    document
211→        .canonical_schema_json()
212→        .map_or_else(
213→            |error| {
214→                warn!(
215→                    error = %error,
216→                    "openai tool schema canonicalization was unavailable; using raw schema for best-effort normalization"
217→                );
218→                input
219→            },
220→            serde_json::Value::clone,
221→        )
222→}
