224→/// Validate and normalize a JSON Schema document into the OpenAI-compatible
225→/// function-calling subset via `json_schema_ast` canonicalization plus
226→/// recursive `schemars` transforms.
227→pub(crate) fn sanitize_schema_for_openai_compat(schema: &mut serde_json::Value) {
228→    let canonical = canonicalize_schema_for_openai_compat(schema);
229→
230→    let Ok(mut transformed) = Schema::try_from(canonical.clone()) else {
231→        *schema = canonical;
232→        return;
233→    };
234→    let mut replace_const = ReplaceConstValue::default();
235→    replace_const.transform(&mut transformed);
236→    let mut replace_unevaluated_properties = ReplaceUnevaluatedProperties::default();
237→    replace_unevaluated_properties.transform(&mut transformed);
238→    let mut replace_prefix_items = ReplacePrefixItems::default();
239→    replace_prefix_items.transform(&mut transformed);
240→    let mut remove_ref_siblings = RemoveRefSiblings::default();
241→    remove_ref_siblings.transform(&mut transformed);
242→    let mut subset_transform = RecursiveTransform(OpenAiSchemaSubsetTransform);
243→    subset_transform.transform(&mut transformed);
244→
245→    // Strip empty `{}` schemas from anyOf/oneOf (left behind by
246→    // canonicalization of `not` and other negation keywords) and collapse
247→    // single-variant composites inline (issue #743).
248→    let mut simplify_composite = RecursiveTransform(SimplifyCompositeTransform);
249→    simplify_composite.transform(&mut transformed);
250→
251→    // Re-infer `"type"` from enum values after canonicalization stripped it.
252→    // Providers like Fireworks AI reject schemas without explicit type
253→    // annotations even when enum values unambiguously imply the type.
254→    let mut restore_enum_type = RecursiveTransform(RestoreEnumTypeTransform);
255→    restore_enum_type.transform(&mut transformed);
256→
257→    *schema = transformed.to_value();
258→}
