 11→/// Agent-callable tool.
 12→#[async_trait]
 13→pub trait AgentTool: Send + Sync {
 14→    fn name(&self) -> &str;
 15→    fn description(&self) -> &str;
 16→    fn parameters_schema(&self) -> serde_json::Value;
 17→    /// Opportunistic post-start initialization hook.
 18→    async fn warmup(&self) -> Result<()> {
 19→        Ok(())
 20→    }
 21→    async fn execute(&self, params: serde_json::Value) -> Result<serde_json::Value>;
