 24→/// Where a tool originates from.
 25→#[derive(Debug, Clone, PartialEq, Eq)]
 26→pub enum ToolSource {
 27→    /// Built-in tool shipped with the binary.
 28→    Builtin,
 29→    /// Tool provided by an MCP server.
 30→    Mcp { server: String },
 31→    /// Tool provided by a precompiled WASM component.
 32→    Wasm { component_hash: [u8; 32] },
 33→}
 34→
 35→/// Internal entry pairing a tool with its source metadata.
 36→pub(crate) struct ToolEntry {
 37→    pub(crate) tool: Arc<dyn AgentTool>,
 38→    pub(crate) source: ToolSource,
 39→}
 40→
 41→/// Shared set of tools activated at runtime by [`ToolSearchTool`](crate::lazy_tools::ToolSearchTool).
 42→///
 43→/// Uses `std::sync::Mutex` (not tokio) because the lock is held for
 44→/// microseconds — just a `HashMap` insert/lookup — and this keeps
 45→/// `list_schemas()` usable from sync contexts.
 46→pub(crate) type ActivatedTools = Arc<Mutex<HashMap<String, ToolEntry>>>;
 47→
 48→/// Registry of available tools for an agent run.
 49→///
 50→/// Tools are stored as `Arc<dyn AgentTool>` so the registry can be cheaply
 51→/// cloned (e.g. for sub-agents that need a filtered copy of the parent's tools).
 52→pub struct ToolRegistry {
 53→    tools: HashMap<String, ToolEntry>,
 54→    /// Tools activated at runtime via lazy tool discovery (`tool_search`).
 55→    /// Always present (empty when lazy mode is not in use).
 56→    pub(crate) activated: ActivatedTools,
 57→}
 58→
 59→impl Default for ToolRegistry {
 60→    fn default() -> Self {
 61→        Self::new()
 62→    }
 63→}
 64→
 65→impl ToolRegistry {
 66→    pub fn new() -> Self {
 67→        Self {
 68→            tools: HashMap::new(),
 69→            activated: Arc::new(Mutex::new(HashMap::new())),
 70→        }
 71→    }
 72→
 73→    /// Register a built-in tool. Warns (and overwrites) on name collision.
 74→    pub fn register(&mut self, tool: Box<dyn AgentTool>) {
 75→        let name = tool.name().to_string();
 76→        let new_source = ToolSource::Builtin;
 77→        if let Some(existing) = self.tools.get(&name) {
 78→            warn!(
 79→                tool = %name,
 80→                old_source = ?existing.source,
 81→                new_source = ?new_source,
 82→                "tool name collision — new registration overwrites existing entry"
 83→            );
 84→        }
 85→        self.tools.insert(name, ToolEntry {
 86→            tool: Arc::from(tool),
 87→            source: new_source,
 88→        });
 89→    }
 90→
 91→    /// Register a tool from an MCP server. Warns (and overwrites) on name collision.
 92→    pub fn register_mcp(&mut self, tool: Box<dyn AgentTool>, server: String) {
 93→        let name = tool.name().to_string();
 94→        let new_source = ToolSource::Mcp { server };
 95→        if let Some(existing) = self.tools.get(&name) {
 96→            warn!(
 97→                tool = %name,
 98→                old_source = ?existing.source,
 99→                new_source = ?new_source,
100→                "tool name collision — new registration overwrites existing entry"
101→            );
102→        }
103→        self.tools.insert(name, ToolEntry {
104→            tool: Arc::from(tool),
105→            source: new_source,
106→        });
107→    }
108→
109→    /// Register a tool from a WASM component. Warns (and overwrites) on name collision.
110→    pub fn register_wasm(&mut self, tool: Box<dyn AgentTool>, component_hash: [u8; 32]) {
111→        let name = tool.name().to_string();
112→        let new_source = ToolSource::Wasm { component_hash };
113→        if let Some(existing) = self.tools.get(&name) {
114→            warn!(
115→                tool = %name,
116→                old_source = ?existing.source,
117→                new_source = ?new_source,
118→                "tool name collision — new registration overwrites existing entry"
119→            );
120→        }
121→        self.tools.insert(name, ToolEntry {
122→            tool: Arc::from(tool),
123→            source: new_source,
124→        });
125→    }
126→
127→    /// Replace an existing tool by name, preserving its source metadata.
128→    ///
129→    /// Returns `true` if an existing tool was replaced, `false` if this was a new entry.
130→    pub fn replace(&mut self, tool: Box<dyn AgentTool>) -> bool {
131→        let name = tool.name().to_string();
132→        let source = self
133→            .tools
134→            .get(&name)
135→            .map(|entry| entry.source.clone())
136→            .unwrap_or(ToolSource::Builtin);
137→        self.tools
138→            .insert(name, ToolEntry {
139→                tool: Arc::from(tool),
140→                source,
141→            })
142→            .is_some()
143→    }
144→
145→    pub fn unregister(&mut self, name: &str) -> bool {
146→        self.tools.remove(name).is_some()
147→    }
148→
149→    /// Remove all MCP-sourced tools. Returns the number of tools removed.
150→    pub fn unregister_mcp(&mut self) -> usize {
151→        let before = self.tools.len();
152→        self.tools
153→            .retain(|_, entry| !matches!(entry.source, ToolSource::Mcp { .. }));
154→        before - self.tools.len()
155→    }
156→
157→    pub fn get(&self, name: &str) -> Option<Arc<dyn AgentTool>> {
158→        if let Some(e) = self.tools.get(name) {
159→            return Some(Arc::clone(&e.tool));
160→        }
161→        let activated = self.activated.lock().unwrap_or_else(|e| e.into_inner());
162→        activated.get(name).map(|e| Arc::clone(&e.tool))
163→    }
164→
165→    /// Return the [`ToolSource`] for a tool by name.
166→    pub(crate) fn get_source(&self, name: &str) -> Option<ToolSource> {
167→        self.tools.get(name).map(|e| e.source.clone())
168→    }
169→
170→    pub fn list_schemas(&self) -> Vec<serde_json::Value> {
171→        let mut schemas: Vec<serde_json::Value> = self
172→            .tools
173→            .iter()
174→            .filter(|(name, _)| is_public_tool_name(name))
175→            .map(|(_, entry)| entry_to_schema(entry))
176→            .collect();
177→
178→        let activated = self.activated.lock().unwrap_or_else(|e| e.into_inner());
179→        for (name, entry) in activated.iter() {
180→            if !self.tools.contains_key(name) && is_public_tool_name(name) {
181→                schemas.push(entry_to_schema(entry));
182→            }
183→        }
184→        schemas.sort_by(|left, right| {
185→            let left_name = left
186→                .get("name")
187→                .and_then(serde_json::Value::as_str)
188→                .unwrap_or("");
189→            let right_name = right
190→                .get("name")
191→                .and_then(serde_json::Value::as_str)
192→                .unwrap_or("");
193→            left_name.cmp(right_name)
194→        });
195→        schemas
196→    }
197→
198→    /// List registered tool names (static + activated).
199→    pub fn list_names(&self) -> Vec<String> {
200→        let mut names: Vec<String> = self

200→        let mut names: Vec<String> = self
201→            .tools
202→            .keys()
203→            .filter(|name| is_public_tool_name(name))
204→            .cloned()
205→            .collect();
206→        let activated = self.activated.lock().unwrap_or_else(|e| e.into_inner());
207→        for name in activated.keys() {
208→            if !self.tools.contains_key(name) && is_public_tool_name(name) {
209→                names.push(name.clone());
210→            }
211→        }
212→        names.sort();
213→        names
214→    }
