216→    /// Clone the registry, excluding tools whose names start with `prefix`.
217→    ///
218→    /// Sub-agent registries get a fresh (empty) activated set.
219→    pub fn clone_without_prefix(&self, prefix: &str) -> ToolRegistry {
220→        let tools = self
221→            .tools
222→            .iter()
223→            .filter(|(name, _)| !name.starts_with(prefix))
224→            .map(|(name, entry)| {
225→                (name.clone(), ToolEntry {
226→                    tool: Arc::clone(&entry.tool),
227→                    source: entry.source.clone(),
228→                })
229→            })
230→            .collect();
231→        ToolRegistry {
232→            tools,
233→            activated: Arc::new(Mutex::new(HashMap::new())),
234→        }
235→    }
236→
237→    /// Clone the registry, excluding all MCP-sourced tools.
238→    pub fn clone_without_mcp(&self) -> ToolRegistry {
239→        let tools = self
240→            .tools
241→            .iter()
242→            .filter(|(_, entry)| !matches!(entry.source, ToolSource::Mcp { .. }))
243→            .map(|(name, entry)| {
244→                (name.clone(), ToolEntry {
245→                    tool: Arc::clone(&entry.tool),
246→                    source: entry.source.clone(),
247→                })
248→            })
249→            .collect();
250→        ToolRegistry {
251→            tools,
252→            activated: Arc::new(Mutex::new(HashMap::new())),
253→        }
254→    }
255→
256→    /// Clone the registry, excluding tools whose names are in `exclude`.
257→    pub fn clone_without(&self, exclude: &[&str]) -> ToolRegistry {
258→        let tools = self
259→            .tools
260→            .iter()
261→            .filter(|(name, _)| !exclude.contains(&name.as_str()))
262→            .map(|(name, entry)| {
263→                (name.clone(), ToolEntry {
264→                    tool: Arc::clone(&entry.tool),
265→                    source: entry.source.clone(),
266→                })
267→            })
268→            .collect();
269→        ToolRegistry {
270→            tools,
271→            activated: Arc::new(Mutex::new(HashMap::new())),
272→        }
273→    }
274→
275→    /// Clone the registry keeping only tools that match `predicate`.
276→    pub fn clone_allowed_by<F>(&self, mut predicate: F) -> ToolRegistry
277→    where
278→        F: FnMut(&str) -> bool,
279→    {
280→        let tools = self
281→            .tools
282→            .iter()
283→            .filter(|(name, _)| predicate(name))
284→            .map(|(name, entry)| {
285→                (name.clone(), ToolEntry {
286→                    tool: Arc::clone(&entry.tool),
287→                    source: entry.source.clone(),
288→                })
289→            })
290→            .collect();
291→        ToolRegistry {
292→            tools,
293→            activated: Arc::new(Mutex::new(HashMap::new())),
294→        }
295→    }
296→}
297→
298→fn is_public_tool_name(name: &str) -> bool {
299→    !name.ends_with("_wasm")
300→}
301→
302→fn entry_to_schema(e: &ToolEntry) -> serde_json::Value {
303→    let mut schema = serde_json::json!({
304→        "name": e.tool.name(),
305→        "description": e.tool.description(),
306→        "parameters": e.tool.parameters_schema(),
307→    });
308→    match &e.source {
309→        ToolSource::Builtin => {
310→            schema["source"] = serde_json::json!("builtin");
311→        },
312→        ToolSource::Mcp { server } => {
313→            schema["source"] = serde_json::json!("mcp");
314→            schema["mcpServer"] = serde_json::json!(server);
315→        },
316→        ToolSource::Wasm { component_hash } => {
317→            schema["source"] = serde_json::json!("wasm");
318→            schema["componentHash"] = serde_json::json!(hex_component_hash(*component_hash));
319→        },
320→    }
321→    schema
322→}
323→
324→fn hex_component_hash(component_hash: [u8; 32]) -> String {
325→    let mut output = String::with_capacity(component_hash.len() * 2);
326→    for byte in component_hash {
327→        use std::fmt::Write as _;
328→        let _ = write!(&mut output, "{byte:02x}");
329→    }
330→    output
331→}
