424→    });
425→
426→    patch_schema_for_strict_mode(&mut schema);
427→
428→    // time_range and country are originally optional, so strict mode makes
429→    // them nullable. The enum array must include null alongside the original
430→    // string values.
431→    let time_range = &schema["properties"]["time_range"];
432→    let Some(time_enum) = time_range["enum"].as_array() else {
433→        panic!("time_range should have enum");
434→    };
