670→/// Issue #743: MCP tools declaring `$schema: "http://json-schema.org/draft-07/schema#"`
671→/// (e.g. Attio) bypass canonicalization entirely because `SchemaDocument::from_json()`
672→/// only accepts Draft 2020-12. Without canonicalization, stripping `not` leaves
673→/// empty `{}` schemas inside `anyOf` which OpenAI rejects ("schema must have a
674→/// 'type' key"). The sanitizer must strip `$schema` before canonicalization so
675→/// that draft-07 schemas get the same AST resolution as draft 2020-12.
676→#[test]
677→fn sanitize_draft07_schema_strips_unsupported_keywords() {
678→    // Reproduces the Attio MCP schema pattern from issue #743:
679→    // nested anyOf with `not` and no `type` key, declared as draft-07.
680→    let mut schema = serde_json::json!({
681→        "$schema": "http://json-schema.org/draft-07/schema#",
682→        "type": "object",
683→        "properties": {
684→            "query": {
685→                "anyOf": [
686→                    {
687→                        "anyOf": [
688→                            {
689→                                "not": {
690→                                    "const": ""
691→                                }
692→                            },
693→                            {
694→                                "type": "string"
695→                            }
696→                        ]
697→                    },
698→                    {
699→                        "type": "null"
700→                    }
701→                ]
702→            }
703→        }
704→    });
