706→    sanitize_schema_for_openai_compat(&mut schema);
707→    let encoded = schema.to_string();
708→
709→    // `$schema` must be stripped.
710→    assert!(
711→        !encoded.contains("$schema"),
712→        "$schema should be removed, got: {encoded}"
713→    );
714→    // `not` must be stripped.
715→    assert!(
716→        !encoded.contains("\"not\""),
717→        "\"not\" should be removed from draft-07 schema, got: {encoded}"
718→    );
719→
720→    // Critical assertion: no empty `{}` schemas left inside anyOf variants.
721→    // Without canonicalization, stripping `not` leaves `{}` which OpenAI
722→    // rejects with "schema must have a 'type' key".
723→    assert!(
724→        !encoded.contains("{}"),
725→        "empty schemas should not remain after sanitization, got: {encoded}"
726→    );
727→    // The root `type: object` must survive.
728→    assert_eq!(schema["type"], "object");
729→}
