}

/// Issue #747: schemas where `required` references properties only defined
/// through `dependentSchemas` (stripped by sanitization) must have those
/// orphaned entries pruned.
#[test]
fn sanitize_prunes_required_from_stripped_dependent_schemas() {
    let mut schema = serde_json::json!({
        "type": "object",
        "properties": {
            "mode": { "type": "string" }
        },
        "dependentSchemas": {
            "mode": {
                "properties": {
                    "extra_param": { "type": "string" }
                }
            }
