/// Issue #747: schemas where `required` references properties only defined
/// through `dependentSchemas` — canonicalization resolves these into the
/// main `properties` object with real schemas, so they survive pruning.
/// The `dependentSchemas` keyword itself must still be stripped.
#[test]
fn sanitize_resolves_dependent_schemas_properties() {
    let mut schema = serde_json::json!({
        "type": "object",
        "properties": {
            "mode": { "type": "string" }
        },
