                }
            }
        },
        "required": ["mode", "extra_param"]
    });

    sanitize_schema_for_openai_compat(&mut schema);

    // Canonicalization resolves `dependentSchemas` into the main properties,
    // so both `mode` and `extra_param` are properly defined.
    let required = schema["required"]
        .as_array()
        .expect("required should be an array");
    let names: Vec<&str> = required.iter().filter_map(|v| v.as_str()).collect();
    assert!(names.contains(&"mode"), "mode should stay in required");
    assert!(
